1	<!DOCTYPE html>
2	<html lang="ru">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
6	<title>Runwise — Программа</title>
7	<link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
8	<style>
9	*, *::before, *::after { margin:0; padding:0; box-sizing:border-box; -webkit-tap-highlight-color:transparent; }
10	
11	:root {
12	  --bg:        #111318;
13	  --card:      #191c24;
14	  --card-hi:   #1c2030;
15	  --border:    #242838;
16	  --border2:   #2d3347;
17	  --text:      #dde2ec;
18	  --sub:       #606880;
19	  --soft:      #8b95aa;
20	  --accent:    #4f8ff7;
21	  --accent-bg: rgba(79,143,247,0.11);
22	  --c-base:    #4f8ff7;
23	  --c-build:   #e8a23a;
24	  --c-peak:    #9b7ff4;
25	  --c-taper:   #3ecf8e;
26	}
27	
28	body {
29	  background: var(--bg);
30	  color: var(--text);
31	  font-family: 'Inter', -apple-system, sans-serif;
32	  -webkit-font-smoothing: antialiased;
33	  display: flex;
34	  justify-content: center;
35	}
36	
37	.app {
38	  width: 100%;
39	  max-width: 430px;
40	  min-height: 100vh;
41	  padding-bottom: 88px;
42	}
43	
44	/* ── TOPBAR ── */
45	.top {
46	  display: flex;
47	  align-items: center;
48	  justify-content: space-between;
49	  padding: 20px 16px 14px;
50	}
51	.top-title { font-size: 21px; font-weight: 700; letter-spacing: -0.3px; }
52	.top-back {
53	  font-size: 14px; font-weight: 500; color: var(--accent);
54	  cursor: pointer; display: flex; align-items: center; gap: 3px;
55	}
56	.top-back svg { width: 16px; height: 16px; }
57	
58	/* ── GOAL CARD ── */
59	.goal {
60	  margin: 0 14px 10px;
61	  background: var(--card);
62	  border: 1px solid var(--border2);
63	  border-radius: 18px;
64	  padding: 16px;
65	  position: relative;
66	  overflow: hidden;
67	}
68	.goal::after {
69	  content: '';
70	  position: absolute; top: -60px; right: -60px;
71	  width: 180px; height: 180px;
72	  background: radial-gradient(circle, rgba(79,143,247,0.07) 0%, transparent 70%);
73	  pointer-events: none;
74	}
75	
76	.g-row1 { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 13px; }
77	
78	.g-name { font-size: 18px; font-weight: 700; letter-spacing: -0.3px; margin-bottom: 3px; }
79	.g-meta { font-size: 13px; color: var(--sub); }
80	
81	.g-time {
82	  font-size: 26px; font-weight: 700; color: var(--accent);
83	  letter-spacing: -1px; line-height: 1; margin-bottom: 3px;
84	  font-variant-numeric: tabular-nums;
85	}
86	.g-until { font-size: 12px; color: var(--sub); text-align: right; }
87	
88	.g-row2 { display: flex; align-items: center; justify-content: space-between; margin-bottom: 14px; }
89	
90	.ph-tag {
91	  font-size: 13px; font-weight: 600; color: var(--accent);
92	  background: var(--accent-bg);
93	  padding: 5px 12px; border-radius: 99px;
94	  display: flex; align-items: center; gap: 5px;
95	}
96	.ph-tag::before { content:''; width:5px; height:5px; border-radius:50%; background:var(--accent); }
97	.g-wn { font-size: 13px; color: var(--sub); }
98	
99	/* track */
100	.track { display: flex; gap: 2px; height: 5px; margin-bottom: 6px; }
101	.seg {
102	  flex: 1; border-radius: 1px; cursor: pointer;
103	  transition: transform 0.12s;
104	}
105	.seg:first-child { border-radius: 3px 1px 1px 3px; }
106	.seg:last-child  { border-radius: 1px 3px 3px 1px; }
107	.seg:hover { transform: scaleY(2); }
108	.seg.ph-base  { background: var(--c-base); }
109	.seg.ph-build { background: var(--c-build); }
110	.seg.ph-peak  { background: var(--c-peak); }
111	.seg.ph-taper { background: var(--c-taper); }
112	.seg.is-done   { opacity: 0.22; }
113	.seg.is-future { opacity: 0.15; }
114	.seg.is-now    { opacity: 1; }
115	.seg.is-now.ph-base  { box-shadow: 0 0 7px var(--c-base); }
116	.seg.is-now.ph-build { box-shadow: 0 0 7px var(--c-build); }
117	.seg.is-now.ph-peak  { box-shadow: 0 0 7px var(--c-peak); }
118	.seg.is-now.ph-taper { box-shadow: 0 0 7px var(--c-taper); }
119	
120	.track-ends { display: flex; justify-content: space-between; }
121	.track-ends span { font-size: 11px; color: var(--sub); }
122	
123	.track-legend { display: flex; gap: 12px; margin-top: 8px; }
124	.tl-item { display: flex; align-items: center; gap: 4px; font-size: 11px; color: var(--sub); font-weight: 500; }
125	.tl-dot  { width: 7px; height: 7px; border-radius: 50%; }
126	
127	/* ── MONTH STATS STRIP ── */
128	.mstats {
129	  margin: 0 14px 4px;
130	  background: var(--card);
131	  border: 1px solid var(--border);
132	  border-radius: 14px;
133	  display: flex;
134	}
135	
136	.ms-item {
137	  flex: 1;
138	  display: flex;
139	  flex-direction: column;
140	  align-items: center;
141	  padding: 13px 8px;
142	  gap: 3px;
143	  position: relative;
144	}
145	
146	.ms-item + .ms-item::before {
147	  content: '';
148	  position: absolute;
149	  left: 0; top: 18%; bottom: 18%;
150	  width: 1px;
151	  background: var(--border);
152	}
153	
154	.ms-val {
155	  font-size: 20px;
156	  font-weight: 700;
157	  letter-spacing: -0.5px;
158	  color: var(--accent);
159	  font-variant-numeric: tabular-nums;
160	  line-height: 1;
161	}
162	.ms-val .ms-unit {
163	  font-size: 13px;
164	  font-weight: 500;
165	  color: var(--sub);
166	  margin-left: 1px;
167	}
168	.ms-lbl { font-size: 12px; color: var(--sub); font-weight: 500; }
169	
170	/* ── MONTH NAV ── */
171	.mnav {
172	  display: flex;
173	  align-items: center;
174	  justify-content: space-between;
175	  padding: 12px 16px 8px;
176	}
177	
178	.mb {
179	  width: 32px; height: 32px;
180	  background: var(--card);
181	  border: 1px solid var(--border2);
182	  border-radius: 10px;
183	  font-size: 18px;
184	  color: var(--accent);
185	  cursor: pointer;
186	  display: flex; align-items: center; justify-content: center;
187	  transition: background 0.15s;
188	}
189	.mb:disabled { color: var(--sub); opacity: 0.4; cursor: default; }
190	.mb:not(:disabled):active { background: var(--card-hi); }
191	
192	.mnav-title { font-size: 16px; font-weight: 700; text-align: center; }
193	
194	/* ── WEEKS ── */
195	.weeks { padding: 0 14px; display: flex; flex-direction: column; }
196	
197	.ph-sep {
198	  display: flex; align-items: center; gap: 8px;
199	  padding: 10px 0 6px;
200	}
201	.ph-sep-line { flex: 1; height: 1px; background: var(--border); }
202	.ph-sep-label {
203	  font-size: 11px; font-weight: 700;
204	  letter-spacing: 1px; text-transform: uppercase;
205	}
206	
207	/* ── WEEK CARD ── */
208	.wk {
209	  background: var(--card);
210	  border: 1px solid var(--border);
211	  border-radius: 16px;
212	  margin-bottom: 8px;
213	  overflow: hidden;
214	  position: relative;
215	  animation: up 0.25s ease both;
216	}
217	@keyframes up {
218	  from { opacity:0; transform:translateY(8px); }
219	  to   { opacity:1; transform:translateY(0); }
220	}
221	
222	.wk.is-past { opacity: 0.42; }
223	
224	/* CURRENT WEEK — stands out */
225	.wk.is-now {
226	  border-color: rgba(79,143,247,0.3);
227	  background: linear-gradient(160deg, #161d2e 0%, #191c24 100%);
228	  box-shadow: 0 4px 24px rgba(79,143,247,0.07);
229	}
230	
231	.wk-strip {
232	  position: absolute; left: 0; top: 0; bottom: 0; width: 3px;
233	}
234	.wk.is-now  .wk-strip { background: var(--accent); }
235	.wk.is-next .wk-strip { background: var(--border2); }
236	
237	.wk-nbg {
238	  position: absolute; right: 10px; bottom: -10px;
239	  font-size: 72px; font-weight: 800; line-height: 1;
240	  letter-spacing: -4px;
241	  color: rgba(255,255,255,0.027);
242	  pointer-events: none; user-select: none;
243	}
244	
245	.wk-body { padding: 15px 14px 14px 15px; }
246	
247	/* head */
248	.wk-head {
249	  display: flex; justify-content: space-between;
250	  align-items: flex-start; margin-bottom: 11px;
251	}
252	
253	.wk-id {
254	  font-size: 15px; font-weight: 700;
255	  display: flex; align-items: center; gap: 7px;
256	  margin-bottom: 4px;
257	}
258	
259	.badge-now {
260	  font-size: 11px; font-weight: 700;
261	  background: var(--accent-bg); color: var(--accent);
262	  padding: 2px 9px; border-radius: 99px;
263	  display: inline-flex; align-items: center; gap: 4px;
264	}
265	.badge-pulse {
266	  width: 5px; height: 5px; border-radius: 50%;
267	  background: var(--accent);
268	  animation: bl 1.8s ease infinite;
269	}
270	@keyframes bl { 0%,100%{opacity:1} 50%{opacity:0.2} }
271	
272	.badge-next {
273	  font-size: 11px; font-weight: 600;
274	  background: rgba(255,255,255,0.05); color: var(--sub);
275	  padding: 2px 9px; border-radius: 99px;
276	}
277	
278	.wk-date { font-size: 13px; color: var(--sub); }
279	
280	.wk-km { text-align: right; flex-shrink: 0; }
281	.wk-km-val {
282	  font-size: 24px; font-weight: 700; color: var(--accent);
283	  letter-spacing: -0.5px; line-height: 1;
284	  font-variant-numeric: tabular-nums;
285	}
286	.wk-km-unit { font-size: 14px; font-weight: 500; color: var(--sub); }
287	.wk-month-pct { font-size: 12px; color: var(--sub); margin-top: 3px; font-variant-numeric: tabular-nums; }
288	
289	/* month progress bar */
290	.month-bar-wrap {
291	  display: flex; align-items: center; gap: 8px; margin-bottom: 12px;
292	}
293	.month-bar-track {
294	  flex: 1; height: 3px; background: var(--border);
295	  border-radius: 2px; overflow: hidden;
296	}
297	.month-bar-fill {
298	  height: 100%; border-radius: 2px;
299	  background: var(--accent); opacity: 0.45;
300	}
301	.month-bar-label {
302	  font-size: 12px; color: var(--sub); white-space: nowrap;
303	  font-variant-numeric: tabular-nums; min-width: 82px; text-align: right;
304	}
305	
306	/* comment */
307	.wk-comment {
308	  font-size: 14px; color: var(--soft);
309	  line-height: 1.55; font-weight: 400;
310	}
311	
312	/* workouts */
313	.wo-toggle {
314	  display: flex; align-items: center; justify-content: space-between;
315	  padding-top: 12px; margin-top: 12px;
316	  border-top: 1px solid var(--border);
317	  font-size: 13px; font-weight: 600;
318	  color: var(--accent); cursor: pointer; user-select: none;
319	}
320	.wo-toggle svg { width: 15px; height: 15px; color: var(--sub); transition: transform 0.22s; }
321	.wo-toggle.open svg { transform: rotate(180deg); }
322	
323	.wo-wrap { overflow: hidden; max-height: 0; transition: max-height 0.3s ease; }
324	.wo-wrap.open { max-height: 700px; }
325	
326	.wo-list { padding-top: 10px; display: flex; flex-direction: column; gap: 7px; }
327	
328	.wo-row {
329	  display: flex; align-items: center; gap: 10px;
330	  padding: 10px 12px;
331	  background: rgba(255,255,255,0.025);
332	  border: 1px solid var(--border); border-radius: 12px;
333	}
334	.wo-day { font-size: 12px; font-weight: 700; color: var(--sub); min-width: 26px; }
335	.wo-info { flex: 1; }
336	.wo-name { font-size: 14px; font-weight: 600; margin-bottom: 2px; }
337	.wo-desc { font-size: 12px; color: var(--sub); }
338	.wo-km   { font-size: 13px; color: var(--soft); font-weight: 500; }
339	
340	/* ── BOTTOM NAV ── */
341	.bnav {
342	  position: fixed; bottom: 0; left: 50%;
343	  transform: translateX(-50%);
344	  width: 100%; max-width: 430px;
345	  background: rgba(17,19,24,0.97);
346	  backdrop-filter: blur(14px);
347	  border-top: 1px solid var(--border);
348	  display: flex; padding: 10px 0 22px; z-index: 50;
349	}
350	.bni {
351	  flex: 1; display: flex; flex-direction: column;
352	  align-items: center; gap: 3px;
353	  color: var(--sub); font-size: 11px; font-weight: 500; cursor: pointer;
354	}
355	.bni.active { color: var(--accent); }
356	.bni-ico { font-size: 20px; }
357	
358	.tip {
359	  position: fixed; background: var(--card-hi);
360	  border: 1px solid var(--border2); border-radius: 8px;
361	  padding: 4px 10px; font-size: 12px; color: var(--text);
362	  pointer-events: none; opacity: 0;
363	  transition: opacity 0.12s; z-index: 999; white-space: nowrap;
364	}
365	</style>
366	</head>
367	<body>
368	<div class="app">
369	
370	  <div class="top">
371	    <div class="top-title">📋 Программа подготовки</div>
372	    <div class="top-back">
373	      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M15 18l-6-6 6-6"/></svg>
374	      К неделе
375	    </div>
376	  </div>
377	
378	  <!-- GOAL -->
379	  <div class="goal">
380	    <div class="g-row1">
381	      <div>
382	        <div class="g-name">Полумарафон</div>
383	        <div class="g-meta">Апрель – Октябрь 2026</div>
384	      </div>
385	      <div>
386	        <div class="g-time">1:30:00</div>
387	        <div class="g-until">26 нед. до старта</div>
388	      </div>
389	    </div>
390	    <div class="g-row2">
391	      <div class="ph-tag">Базовая фаза</div>
392	      <div class="g-wn">нед. 1 из 27</div>
393	    </div>
394	    <div class="track" id="track"></div>
395	    <div class="track-ends"><span>Апр 2026</span><span>Ноя 2026</span></div>
396	    <div class="track-legend">
397	      <div class="tl-item"><div class="tl-dot" style="background:var(--c-base)"></div>База</div>
398	      <div class="tl-item"><div class="tl-dot" style="background:var(--c-build)"></div>Развитие</div>
399	      <div class="tl-item"><div class="tl-dot" style="background:var(--c-peak)"></div>Пик</div>
400	      <div class="tl-item"><div class="tl-dot" style="background:var(--c-taper)"></div>Подводка</div>
401	    </div>
402	  </div>
403	
404	  <!-- MONTH STATS -->
405	  <div class="mstats" id="mstats"></div>
406	
407	  <!-- MONTH NAV -->
408	  <div class="mnav">
409	    <button class="mb" id="pBtn" onclick="go(-1)">‹</button>
410	    <div class="mnav-title" id="mTitle">Июнь 2026</div>
411	    <button class="mb" id="nBtn" onclick="go(1)">›</button>
412	  </div>
413	
414	  <div class="weeks" id="weeks"></div>
415	</div>
416	
417	<div class="bnav">
418	  <div class="bni"><div class="bni-ico">🏠</div>Главная</div>
419	  <div class="bni"><div class="bni-ico">📅</div>История</div>
420	  <div class="bni active"><div class="bni-ico">📋</div>План</div>
421	  <div class="bni"><div class="bni-ico">🤖</div>AI</div>
422	  <div class="bni"><div class="bni-ico">👤</div>Профиль</div>
423	</div>
424	
425	<div class="tip" id="tip"></div>
426	
427	<script>
428	const MN = ['Январь','Февраль','Март','Апрель','Май','Июнь','Июль','Август','Сентябрь','Октябрь','Ноябрь','Декабрь'];
429	const NOW = 9, MIN_M = 3, MAX_M = 9;
430	let month = 6;
431	
432	const PH_LABEL = { base:'Базовый блок', build:'Развитие', peak:'Пик', taper:'Подводка' };
433	const PH_COLOR = { base:'var(--c-base)', build:'var(--c-build)', peak:'var(--c-peak)', taper:'var(--c-taper)' };
434	
435	const W = [
436	  { id:1,  m:3, ph:'base',  km:35, d:'31 мар – 6 апр',   rest:2, train:5, past:true,  comment:'Первая неделя. Всё на лёгком пульсе — просто привыкаем к режиму.' },
