439	  { id:4,  m:4, ph:'base',  km:44, d:'21 – 27 апр',      rest:2, train:5, past:true,  comment:'Длинная 20 км. Следи за темпом — он должен даваться легко.' },
440	  { id:5,  m:4, ph:'base',  km:40, d:'28 апр – 4 май',   rest:2, train:5, past:true,  comment:'Разгрузочная неделя −10%. Организм адаптируется — не мешай ему.' },
441	  { id:6,  m:5, ph:'build', km:50, d:'5 – 11 май',       rest:2, train:5, past:true,  comment:'Заходим в развитие. Объём прыгает, появляется настоящий темп.' },
442	  { id:7,  m:5, ph:'build', km:54, d:'12 – 18 май',      rest:2, train:5, past:true,  comment:'Первые интервалы 6×800 м. Темп 4:45/км. Длинная 28 км.' },
443	  { id:8,  m:5, ph:'build', km:56, d:'19 – 25 май',      rest:2, train:5, past:true,  comment:'Двойные качественные за неделю. Темп уже 4:35/км — работаем серьёзно.' },
444	  {
445	    id:9,  m:6, ph:'build', km:58, d:'1 – 7 июн', rest:2, train:5, now:true,
446	    comment:'Максимальный объём блока развития. Длинная 29 км в аэробной зоне. Не гони темп на длинной — важен километраж.',
