451	      { day:'Сб', name:'Длинная',           desc:'29 км · пульс 140–152', km:'29 км' },
452	    ]
453	  },
454	  {
455	    id:10, m:6, ph:'build', km:55, d:'8 – 14 июн', rest:2, train:5, next:true,
456	    comment:'Небольшая разгрузка −5%, но качество не теряем. Интервалы 8×600 м и фартлек в пятницу по ощущению.',
457	    wo:[
458	      { day:'Пн', name:'Восстановительный', desc:'7 км · пульс ≤130', km:'7 км' },
459	      { day:'Ср', name:'Интервальный',      desc:'8×600 м / 4:50 + разминка', km:'10 км' },
460	      { day:'Пт', name:'Фартлек',           desc:'45 мин · по ощущению', km:'8 км' },
461	      { day:'Вс', name:'Длинная',           desc:'29 км · пульс 145', km:'29 км' },
462	    ]
463	  },
464	  { id:11, m:6, ph:'build', km:60, d:'15 – 21 июн', rest:2, train:5, comment:'Новый пик объёма. Две качественные работы за неделю — готовься морально.' },
465	  { id:12, m:6, ph:'build', km:58, d:'22 – 28 июн', rest:2, train:5, comment:'Завершаем блок развития. Чуть снижаем — следующий месяц будет тяжелее.' },
