481	];
482	
483	function monthStats(m) {
484	  const ws = W.filter(w => w.m === m);
485	  return {
486	    km:    ws.reduce((s,w) => s + w.km, 0),
487	    train: ws.reduce((s,w) => s + (w.train||5), 0),
488	    rest:  ws.reduce((s,w) => s + (w.rest||2), 0),
489	  };
490	}
491	
492	function monthTotal(m) { return W.filter(w => w.m === m).reduce((s,w) => s+w.km, 0); }
493	
494	function monthCumulative(wId, m) {
495	  return W.filter(w => w.m === m && w.id <= wId).reduce((s,w) => s+w.km, 0);
496	}
497	
498	function renderStats() {
499	  const s = monthStats(month);
500	  document.getElementById('mstats').innerHTML = `
501	    <div class="ms-item">
502	      <div class="ms-val">${s.km}<span class="ms-unit">км</span></div>
503	      <div class="ms-lbl">За месяц</div>
504	    </div>
505	    <div class="ms-item">
506	      <div class="ms-val">${s.train}<span class="ms-unit">дн</span></div>
507	      <div class="ms-lbl">Тренировок</div>
508	    </div>
509	    <div class="ms-item">
510	      <div class="ms-val">${s.rest}<span class="ms-unit">дн</span></div>
511	      <div class="ms-lbl">Отдыха</div>
512	    </div>
513	  `;
514	}
515	
516	function buildTrack() {
517	  const track = document.getElementById('track');
518	  const tip = document.getElementById('tip');
519	  W.forEach(w => {
520	    const s = document.createElement('div');
521	    const state = w.id < NOW ? 'is-done' : w.id === NOW ? 'is-now' : 'is-future';
522	    s.className = `seg ph-${w.ph} ${state}`;
523	    s.addEventListener('mouseenter', () => { tip.textContent = `Н${w.id} · ${w.km} км`; tip.style.opacity = '1'; });
524	    s.addEventListener('mousemove', e => { tip.style.left = e.clientX+10+'px'; tip.style.top = e.clientY-30+'px'; });
525	    s.addEventListener('mouseleave', () => { tip.style.opacity = '0'; });
526	    track.appendChild(s);
527	  });
528	}
529	
530	function render() {
531	  const el = document.getElementById('weeks');
532	  el.innerHTML = '';
533	  const ws = W.filter(w => w.m === month);
534	  const total = monthTotal(month);
535	  let lastPh = null;
536	
537	  ws.forEach((w, i) => {
538	    if (w.ph !== lastPh) {
539	      lastPh = w.ph;
540	      const sep = document.createElement('div');
541	      sep.className = 'ph-sep';
542	      sep.innerHTML = `<div class="ph-sep-line"></div><span class="ph-sep-label" style="color:${PH_COLOR[w.ph]}">${PH_LABEL[w.ph]}</span><div class="ph-sep-line"></div>`;
543	      el.appendChild(sep);
544	    }
545	
546	    const cumKm  = monthCumulative(w.id, month);
547	    const cumPct = Math.round(cumKm / total * 100);
548	    const volPct = Math.round(w.km / total * 100);
549	
550	    let badge = '';
551	    if (w.now)  badge = `<span class="badge-now"><span class="badge-pulse"></span>Сейчас</span>`;
552	    if (w.next) badge = `<span class="badge-next">Следующая</span>`;
553	
554	    let woHtml = '';
555	    if ((w.now || w.next) && w.wo) {
556	      const wid = `wo${w.id}`, tid = `tg${w.id}`;
557	      const rows = w.wo.map(r => `
558	        <div class="wo-row">
559	          <div class="wo-day">${r.day}</div>
560	          <div class="wo-info">
561	            <div class="wo-name">${r.name}</div>
562	            <div class="wo-desc">${r.desc}</div>
563	          </div>
564	          <div class="wo-km">${r.km}</div>
565	        </div>`).join('');
566	      woHtml = `
567	        <div class="wo-toggle" id="${tid}" onclick="tog('${wid}','${tid}')">
568	          Тренировки недели
569	          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M6 9l6 6 6-6"/></svg>
570	        </div>
571	        <div class="wo-wrap" id="${wid}"><div class="wo-list">${rows}</div></div>`;
572	    }
573	
574	    const card = document.createElement('div');
575	    card.className = `wk${w.past?' is-past':''}${w.now?' is-now':''}${w.next?' is-next':''}`;
576	    card.style.animationDelay = `${i * 0.045}s`;
577	
578	    card.innerHTML = `
579	      <div class="wk-strip"></div>
580	      <div class="wk-nbg">${w.id}</div>
581	      <div class="wk-body">
582	        <div class="wk-head">
583	          <div>
584	            <div class="wk-id">Неделя ${w.id} ${badge}</div>
585	            <div class="wk-date">${w.d}</div>
586	          </div>
587	          <div class="wk-km">
588	            <div class="wk-km-val">${w.km}<span class="wk-km-unit"> км</span></div>
589	            <div class="wk-month-pct">${volPct}% от месяца</div>
590	          </div>
591	        </div>
592	        <div class="month-bar-wrap">
593	          <div class="month-bar-track">
594	            <div class="month-bar-fill" style="width:${cumPct}%"></div>
595	          </div>
596	          <div class="month-bar-label">${cumKm} из ${total} км</div>
597	        </div>
598	        ${w.comment ? `<div class="wk-comment">${w.comment}</div>` : ''}
599	        ${woHtml}
600	      </div>`;
601	
602	    el.appendChild(card);
603	  });
604	}
605	
606	function tog(wid, tid) {
607	  document.getElementById(wid).classList.toggle('open');
608	  document.getElementById(tid).classList.toggle('open');
609	}
610	
611	function go(d) {
612	  month = Math.max(MIN_M, Math.min(MAX_M, month + d));
613	  document.getElementById('mTitle').textContent = MN[month] + ' 2026';
614	  document.getElementById('pBtn').disabled = month === MIN_M;
615	  document.getElementById('nBtn').disabled = month === MAX_M;
616	  renderStats();
617	  render();
618	}
619	
620	buildTrack();
621	renderStats();
622	render();
623	document.getElementById('pBtn').disabled = month === MIN_M;
624	document.getElementById('nBtn').disabled = month === MAX_M;
625	</script>
626	</body>
627	</html>
