20	  id: string;
21	  goal_type: string;
22	  goal_target_value: number;
23	  race_date: string | null;
24	  total_weeks: number;
25	  current_week: number;
26	  status: string;
27	  weeks: MacroPlanWeek[];
28	}
29	
30	interface MacroPlanTimelineProps {
31	  macroPlan: MacroPlan;
32	}
33	
34	const LOCALE_MAP: Record<string, string> = { ru: 'ru-RU', uk: 'uk-UA', en: 'en-US' };
35	
36	const GOAL_NAMES: Record<string, Record<string, string>> = {
37	  ru: { pb_5k: '5 km', pb_10k: '10 km', pb_21k: 'Полумарафон', pb_42k: 'Марафон', monthly_distance: 'Месячный объём', weekly_distance: 'Недельный объём' },
38	  uk: { pb_5k: '5 km', pb_10k: '10 km', pb_21k: 'Півмарафон', pb_42k: 'Марафон', monthly_distance: "Місячний об'єм", weekly_distance: "Тижневий об'єм" },
39	  en: { pb_5k: '5K', pb_10k: '10K', pb_21k: 'Half Marathon', pb_42k: 'Marathon', monthly_distance: 'Monthly volume', weekly_distance: 'Weekly volume' }
40	};
41	
42	function formatTime(seconds: number): string {
43	  const h = Math.floor(seconds / 3600);
44	  const m = Math.floor((seconds % 3600) / 60);
45	  const s = Math.round(seconds % 60);
46	  return h > 0
47	    ? `${h}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`
48	    : `${m}:${s.toString().padStart(2, '0')}`;
49	}
50	
51	const MacroPlanTimeline: React.FC<MacroPlanTimelineProps> = ({ macroPlan }) => {
52	  const { t } = useTranslation();
53	  const [selectedWeek, setSelectedWeek] = useState<number | null>(null);
54	  const timelineRef = useRef<HTMLDivElement>(null);
55	  const currentWeekRef = useRef<HTMLDivElement>(null);
56	
57	  const lang = i18n.language || 'ru';
58	  const locale = LOCALE_MAP[lang] || 'ru-RU';
59	  const weeks = macroPlan.weeks;
60	  const currentWeek = macroPlan.current_week;
61	
62	  // Scroll to current week on mount
63	  useEffect(() => {
64	    if (currentWeekRef.current && timelineRef.current) {
65	      const container = timelineRef.current;
66	      const el = currentWeekRef.current;
67	      const scrollLeft = el.offsetLeft - container.clientWidth / 2 + el.clientWidth / 2;
68	      container.scrollTo({ left: Math.max(0, scrollLeft), behavior: 'smooth' });
69	    }
70	  }, [currentWeek]);
71	
72	  // Goal display
73	  const goalNames = GOAL_NAMES[lang] || GOAL_NAMES.ru;
74	  const goalName = goalNames[macroPlan.goal_type] || macroPlan.goal_type;
75	  const isPB = ['pb_5k', 'pb_10k', 'pb_21k', 'pb_42k'].includes(macroPlan.goal_type);
76	  const targetStr = isPB ? formatTime(macroPlan.goal_target_value) : `${(macroPlan.goal_target_value / 1000).toFixed(0)} ${t('macroPlan.km')}`;
77	
78	  // Race date
79	  const raceDateStr = macroPlan.race_date
80	    ? new Date(macroPlan.race_date).toLocaleDateString(locale, { day: 'numeric', month: 'short' })
81	    : null;
82	
83	  // Weeks left
84	  const weeksLeft = macroPlan.total_weeks - currentWeek;
85	
86	  // Current phase
87	  const currentWeekData = weeks[currentWeek - 1];
