51	  uk: ['Січень','Лютий','Березень','Квітень','Травень','Червень','Липень','Серпень','Вересень','Жовтень','Листопад','Грудень'],
52	  en: ['January','February','March','April','May','June','July','August','September','October','November','December']
53	};
