61	function formatTime(seconds: number): string {
62	  const h = Math.floor(seconds / 3600);
63	  const m = Math.floor((seconds % 3600) / 60);
64	  const s = Math.round(seconds % 60);
65	  return h > 0
66	    ? `${h}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`
67	    : `${m}:${s.toString().padStart(2, '0')}`;
68	}
