77	  // Goal info
78	  const goalNames = GOAL_NAMES[lang] || GOAL_NAMES.ru;
79	  const goalName = goalNames[macroPlan.goal_type] || macroPlan.goal_type;
80	  const isPB = ['pb_5k', 'pb_10k', 'pb_21k', 'pb_42k'].includes(macroPlan.goal_type);
