/* ============ MACRO PLAN VIEW (full-screen) ============ */

.mpv {
  padding-bottom: 20px;
}

/* ── TOPBAR ── */
.mpv-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 0 14px;
}

.mpv-top-title {
  font-size: 21px;
  font-weight: 700;
  letter-spacing: -0.3px;
}

.mpv-top-back {
  font-size: 14px;
  font-weight: 500;
  color: var(--color-accent);
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 3px;
  background: none;
  border: none;
  padding: 0;
}

.mpv-top-back svg {
  width: 16px;
  height: 16px;
}

/* ── GOAL CARD ── */
.mpv-goal {
  background: var(--color-bg-secondary);
  border: 1px solid var(--color-border);
  border-radius: 18px;
  padding: 16px;
  position: relative;
  overflow: hidden;
  margin-bottom: 10px;
