}

.mpv-ph-sep-label.phase-base { color: var(--color-accent); }
.mpv-ph-sep-label.phase-build { color: var(--color-warning); }
.mpv-ph-sep-label.phase-peak { color: var(--color-danger); }
.mpv-ph-sep-label.phase-taper { color: var(--color-success); }
.mpv-ph-sep-label.phase-race { color: var(--color-danger); }

/* ── WEEK CARD ── */
.mpv-wk {
  background: var(--color-bg-secondary);
  border: 1px solid var(--color-border);
  border-radius: 16px;
  margin-bottom: 8px;
  overflow: hidden;
  position: relative;
  animation: mpvUp 0.25s ease both;
}

@keyframes mpvUp {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

.mpv-wk.is-past { opacity: 0.42; }

.mpv-wk.is-now {
  border-color: rgba(59, 130, 246, 0.3);
  background: linear-gradient(160deg, #161d2e 0%, var(--color-bg-secondary) 100%);
  box-shadow: 0 4px 24px rgba(59, 130, 246, 0.07);
}

.mpv-wk-strip {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 3px;
}

.mpv-wk.is-now .mpv-wk-strip { background: var(--color-accent); }
.mpv-wk.is-next .mpv-wk-strip { background: var(--color-border); }

.mpv-wk-nbg {
  position: absolute;
  right: 10px;
  bottom: -10px;
  font-size: 72px;
  font-weight: 800;
  line-height: 1;
  letter-spacing: -4px;
  color: rgba(255, 255, 255, 0.027);
  pointer-events: none;
  user-select: none;
}

.mpv-wk-body { padding: 15px 14px 14px 15px; }

.mpv-wk-head {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 11px;
}

.mpv-wk-id {
  font-size: 15px;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 7px;
  margin-bottom: 4px;
}

.mpv-badge-now {
  font-size: 11px;
  font-weight: 700;
  background: rgba(59, 130, 246, 0.11);
  color: var(--color-accent);
  padding: 2px 9px;
  border-radius: 99px;
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

.mpv-badge-pulse {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: var(--color-accent);
  animation: mpvBlink 1.8s ease infinite;
}

@keyframes mpvBlink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.2; }
}

.mpv-badge-next {
  font-size: 11px;
  font-weight: 600;
  background: rgba(255, 255, 255, 0.05);
  color: var(--color-text-secondary);
  padding: 2px 9px;
  border-radius: 99px;
}

.mpv-wk-date {
  font-size: 13px;
  color: var(--color-text-secondary);
}

.mpv-wk-km {
  text-align: right;
  flex-shrink: 0;
}

.mpv-wk-km-val {
  font-size: 24px;
  font-weight: 700;
  color: var(--color-accent);
  letter-spacing: -0.5px;
  line-height: 1;
  font-variant-numeric: tabular-nums;
}

.mpv-wk-km-unit {
  font-size: 14px;
  font-weight: 500;
  color: var(--color-text-secondary);
}

.mpv-wk-month-pct {
  font-size: 12px;
  color: var(--color-text-secondary);
  margin-top: 3px;
  font-variant-numeric: tabular-nums;
}

/* month progress bar in week card */
.mpv-month-bar-wrap {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 12px;
}

.mpv-month-bar-track {
  flex: 1;
  height: 3px;
  background: var(--color-border);
  border-radius: 2px;
  overflow: hidden;
}

.mpv-month-bar-fill {
  height: 100%;
  border-radius: 2px;
  background: var(--color-accent);
  opacity: 0.45;
}

.mpv-month-bar-label {
  font-size: 12px;
  color: var(--color-text-secondary);
  white-space: nowrap;
  font-variant-numeric: tabular-nums;
  min-width: 82px;
  text-align: right;
}

/* comment */
.mpv-wk-comment {
  font-size: 14px;
  color: var(--color-text-secondary);
  line-height: 1.55;
  font-weight: 400;
}

/* workouts toggle */
.mpv-wo-toggle {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: 12px;
  margin-top: 12px;
  border-top: 1px solid var(--color-border);
  font-size: 13px;
  font-weight: 600;
  color: var(--color-accent);
  cursor: pointer;
  user-select: none;
  background: none;
  border-left: none;
  border-right: none;
  border-bottom: none;
  width: 100%;
  text-align: left;
}

.mpv-wo-toggle svg {
  width: 15px;
  height: 15px;
  color: var(--color-text-secondary);
  transition: transform 0.22s;
}

.mpv-wo-toggle.open svg { transform: rotate(180deg); }

.mpv-wo-wrap {
  overflow: hidden;
  max-height: 0;
  transition: max-height 0.3s ease;
}

.mpv-wo-wrap.open { max-height: 700px; }

.mpv-wo-list {
  padding-top: 10px;
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.mpv-wo-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  background: rgba(255, 255, 255, 0.025);
  border: 1px solid var(--color-border);
  border-radius: 12px;
}

.mpv-wo-day {
  font-size: 12px;
  font-weight: 700;
  color: var(--color-text-secondary);
  min-width: 26px;
}

.mpv-wo-info { flex: 1; }

.mpv-wo-name {
  font-size: 14px;
  font-weight: 600;
  margin-bottom: 2px;
}

.mpv-wo-desc {
  font-size: 12px;
  color: var(--color-text-secondary);
}

.mpv-wo-km {
  font-size: 13px;
  color: var(--color-text-secondary);
  font-weight: 500;
}
